/*Table structure for table `syllabi` */

DROP TABLE IF EXISTS `syllabi`;

CREATE TABLE `syllabi` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `text` longtext NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=79 DEFAULT CHARSET=utf8mb4;

/*Data for the table `syllabi` */

insert  into `syllabi`(`id`,`title`,`text`,`created_at`) values (42,'Deep Learning (AIDS – 7th Semester)','UNIT I: Neural Network Fundamentals\nPerceptron, Activation Functions, Loss Functions.\nGradient Descent, Backpropagation.\nUNIT II: CNN Architectures\nConvolution, Pooling, Padding, Stride.\nLeNet, AlexNet, VGG, ResNet.\nUNIT III: RNN and Sequence Models\nRNN, LSTM, GRU.\nSequence-to-Sequence, Attention Mechanism.\nUNIT IV: Optimization and Regularization\nDropout, Batch Normalization, Data Augmentation.\nAdam, RMSprop, Learning Rate Scheduling.\nUNIT V: Deployment and Applications\nTransfer Learning, Fine-Tuning.\nModel Export: ONNX/TFLite.\nApplications: Image Classification, NLP, Speech.','2026-02-05 04:18:21'),(43,'Python Programming','UNIT I: Python Fundamentals\r\nSyntax, Variables, Data Types.\r\nOperators, Conditional Statements, Loops.\r\n\r\nUNIT II: Functions and Data Structures\r\nFunctions, Lambda, Recursion.\r\nLists, Tuples, Sets, Dictionaries.\r\n\r\nUNIT III: OOP in Python\r\nClasses and Objects, Inheritance.\r\nPolymorphism, Encapsulation.\r\n\r\nUNIT IV: File Handling and Modules\r\nReading/Writing Files.\r\nModules, Packages, Exception Handling.\r\n\r\nUNIT V: Libraries for Data Science\r\nNumPy Basics, Pandas Basics.\r\nMatplotlib Basics, Introduction to ML with sklearn.','2026-02-25 01:48:33'),(44,'Digital Electronics','UNIT I: Number Systems\r\nBinary, Octal, Decimal, Hexadecimal.\r\nBoolean Algebra, Logic Gates.\r\n\r\nUNIT II: Combinational Circuits\r\nK-Map Simplification.\r\nAdders, Subtractors, Multiplexers, Encoders, Decoders.\r\n\r\nUNIT III: Sequential Circuits\r\nFlip-Flops, Registers, Counters.\r\nShift Registers, Timing Diagrams.\r\n\r\nUNIT IV: Memory Devices\r\nROM, RAM, PROM, EPROM.\r\nMemory Organization.\r\n\r\nUNIT V: Digital ICs and Applications\r\nPLDs, CPLDs, FPGA Basics.\r\nApplications in Communication and Computing.','2026-02-27 11:10:16'),(45,'Deep Learning','UNIT I: Neural Network Fundamentals\nPerceptron, Activation Functions, Loss Functions.\nGradient Descent, Backpropagation.\nUNIT II: CNN Architectures\nConvolution, Pooling, Padding, Stride.\nLeNet, AlexNet, VGG, ResNet.\nUNIT III: RNN and Sequence Models\nRNN, LSTM, GRU.\nSequence-to-Sequence, Attention Mechanism.\nUNIT IV: Optimization and Regularization\nDropout, Batch Normalization, Data Augmentation.\nAdam, RMSprop, Learning Rate Scheduling.\nUNIT V: Deployment and Applications\nTransfer Learning, Fine-Tuning.\nModel Export: ONNX/TFLite.\nApplications: Image Classification, NLP, Speech.','2026-02-27 16:32:33'),(46,'cryptography network','RSA algorithms','2026-02-27 16:39:01'),(47,'CNS','RSA algorithms','2026-02-27 16:41:15'),(48,'CNS','RSA algorithms','2026-02-27 16:42:50'),(49,'Cryptography network system','RSA algorithms','2026-02-27 16:43:28'),(50,'Cryptography network system','RSA algorithms','2026-02-27 16:43:30'),(51,'cloud computing','UNIT I: Cloud Fundamentals\r\nCloud Concepts, Service Models (IaaS, PaaS, SaaS).\r\nDeployment Models: Public, Private, Hybrid Cloud.\r\n\r\nUNIT II: Virtualization\r\nHypervisors, Virtual Machines, Containers.\r\nDocker Basics, Containerization.\r\n\r\nUNIT III: Cloud Architecture\r\nCloud Storage, Cloud Networking.\r\nLoad Balancing, Auto Scaling.\r\n\r\nUNIT IV: Security in Cloud\r\nCloud Security Issues, IAM, Encryption.\r\nData Privacy, Compliance.\r\n\r\nUNIT V: Cloud Platforms\r\nAWS Overview, Azure Overview, Google Cloud Basics.\r\nServerless Computing, Cloud Monitoring.','2026-02-27 23:20:28'),(52,'Deep Learning','UNIT I: Neural Network Fundamentals\nPerceptron, Activation Functions, Loss Functions.\nGradient Descent, Backpropagation.\nUNIT II: CNN Architectures\nConvolution, Pooling, Padding, Stride.\nLeNet, AlexNet, VGG, ResNet.\nUNIT III: RNN and Sequence Models\nRNN, LSTM, GRU.\nSequence-to-Sequence, Attention Mechanism.\nUNIT IV: Optimization and Regularization\nDropout, Batch Normalization, Data Augmentation.\nAdam, RMSprop, Learning Rate Scheduling.\nUNIT V: Deployment and Applications\nTransfer Learning, Fine-Tuning.\nModel Export: ONNX/TFLite.\nApplications: Image Classification, NLP, Speech.','2026-02-28 08:59:09'),(53,'Digital Electronics','UNIT I: Number Systems\r\nBinary, Octal, Decimal, Hexadecimal.\r\nBoolean Algebra, Logic Gates.\r\n\r\nUNIT II: Combinational Circuits\r\nK-Map Simplification.\r\nAdders, Subtractors, Multiplexers, Encoders, Decoders.\r\n\r\nUNIT III: Sequential Circuits\r\nFlip-Flops, Registers, Counters.\r\nShift Registers, Timing Diagrams.\r\n\r\nUNIT IV: Memory Devices\r\nROM, RAM, PROM, EPROM.\r\nMemory Organization.\r\n\r\nUNIT V: Digital ICs and Applications\r\nPLDs, CPLDs, FPGA Basics.\r\nApplications in Communication and Computing.','2026-02-28 09:10:53'),(54,'data structure','arrays,linked list,stack','2026-02-28 09:17:50'),(55,'data structure','arrays,linked list,stack','2026-02-28 09:18:11'),(56,'data structure','Unit 1\r\narrays,linked_list,stack\r\n\r\nunit 2\r\ntrees','2026-02-28 09:19:21'),(57,'python programmimg','UNIT I: Python Fundamentals\r\nSyntax, Variables, Data Types.\r\nOperators, Conditional Statements, Loops.\r\n\r\nUNIT II: Functions and Data Structures\r\nFunctions, Lambda, Recursion.\r\nLists, Tuples, Sets, Dictionaries.\r\n\r\nUNIT III: OOP in Python\r\nClasses and Objects, Inheritance.\r\nPolymorphism, Encapsulation.\r\n\r\nUNIT IV: File Handling and Modules\r\nReading/Writing Files.\r\nModules, Packages, Exception Handling.\r\n\r\nUNIT V: Libraries for Data Science\r\nNumPy Basics, Pandas Basics.\r\nMatplotlib Basics, Introduction to ML with sklearn.','2026-02-28 09:21:28'),(58,'cryptography system','RSA algorithms','2026-02-28 09:27:59'),(59,'Data Structure and Algorithms','UNIT I: Introduction to Data Structures\r\nBasic Concepts, Abstract Data Types (ADT), Algorithm Analysis, Time Complexity, Space Complexity.\r\nArrays: Operations, Searching, Sorting basics.\r\nStrings: String operations, Pattern matching basics.\r\n\r\nUNIT II: Linear Data Structures\r\nStacks: Applications, Infix to Postfix, Recursion.\r\nQueues: Circular Queue, Priority Queue, Deque.\r\nLinked List: Singly Linked List, Doubly Linked List, Circular Linked List.\r\n\r\nUNIT III: Non-Linear Data Structures\r\nTrees: Terminology, Binary Tree, Traversals (Inorder, Preorder, Postorder).\r\nBinary Search Tree (BST): Operations, Insertion, Deletion.\r\nHeaps: Min Heap, Max Heap, Heap Sort.\r\n\r\nUNIT IV: Graphs\r\nGraph Representation: Adjacency Matrix, Adjacency List.\r\nGraph Traversal: BFS, DFS.\r\nShortest Path: Dijkstra Algorithm.\r\nMinimum Spanning Tree: Prim’s Algorithm, Kruskal Algorithm.\r\n\r\nUNIT V: Searching and Sorting\r\nSearching: Linear Search, Binary Search.\r\nSorting: Bubble Sort, Selection Sort, Insertion Sort, Merge Sort, Quick Sort.\r\nHashing: Hash functions, Collision resolution techniques.','2026-02-28 09:31:08'),(60,'data structure','arrays','2026-02-28 13:47:45'),(61,'electronic device  circuit','8*1 max \r\nP-N junction diodes','2026-02-28 13:52:51'),(62,'Database Management Systems','UNIT I: Introduction to DBMS\r\nDatabase Concepts, DBMS Architecture, Data Models, ER Model, Schema and Instances.\r\nRelational Model, Keys, Constraints.\r\n\r\nUNIT II: Relational Algebra and SQL\r\nRelational Algebra operations.\r\nSQL: DDL, DML, DCL, TCL.\r\nJoins, Nested Queries, Views, Indexes.\r\n\r\nUNIT III: Database Design\r\nFunctional Dependencies, Normalization (1NF, 2NF, 3NF, BCNF).\r\nDecomposition, Lossless Join, Dependency Preservation.\r\n\r\nUNIT IV: Transaction Management\r\nTransactions, ACID Properties.\r\nConcurrency Control, Locking, Deadlocks.\r\nRecovery Techniques, Log-based recovery.\r\n\r\nUNIT V: Advanced Concepts\r\nStored Procedures, Triggers.\r\nNoSQL Overview.\r\nDatabase Security and Authorization.','2026-02-28 13:54:49'),(63,'Structural Analysis','UNIT I: Introduction to Structural Analysis\r\nTypes of Structures, Loads, Support Conditions.\r\nStatic Determinacy.\r\n\r\nUNIT II: Shear Force and Bending Moment\r\nSFD and BMD for Beams.\r\nPoint Loads, UDL, UVL.\r\n\r\nUNIT III: Trusses\r\nAnalysis of Simple Trusses.\r\nMethod of Joints, Method of Sections.\r\n\r\nUNIT IV: Deflection of Beams\r\nDouble Integration Method.\r\nMacaulay’s Method.\r\n\r\nUNIT V: Indeterminate Structures\r\nSlope Deflection Method.\r\nMoment Distribution Method.','2026-02-28 14:05:19'),(64,'Operating Systems','UNIT I: OS Overview\r\nOperating System Functions, System Calls, OS Structures.\r\nProcess Concepts, Process Scheduling, Context Switching.\r\n\r\nUNIT II: CPU Scheduling\r\nScheduling Criteria, FCFS, SJF, Round Robin, Priority Scheduling.\r\nMultilevel Queue Scheduling, Multilevel Feedback Queue.\r\n\r\nUNIT III: Memory Management\r\nPaging, Segmentation, Virtual Memory.\r\nPage Replacement Algorithms: FIFO, LRU, Optimal.\r\n\r\nUNIT IV: Deadlocks and Synchronization\r\nCritical Section Problem, Semaphores, Monitors.\r\nDeadlocks: Conditions, Prevention, Avoidance, Detection.\r\n\r\nUNIT V: File and I/O Management\r\nFile System Structure, Directory Implementation.\r\nDisk Scheduling: FCFS, SSTF, SCAN, C-SCAN.\r\nI/O Systems and Device Management.','2026-02-28 14:10:24'),(65,'operating system','deadlock','2026-02-28 16:14:22'),(66,'operating system','deadlock','2026-02-28 16:19:14'),(67,'operating system','deadlock','2026-02-28 16:22:34'),(68,'operating system','Deadlock','2026-02-28 16:23:05'),(69,'Operating System','Deadlock','2026-02-28 16:23:24'),(70,'Operating System','fundamental os\r\nDeadlock','2026-02-28 16:27:04'),(71,'Operating System','UNIT 1\r\nfundamental os\r\nDeadlock','2026-02-28 16:27:24'),(72,'Operating System','UNIT 1\r\nfundamental os\r\nDeadlock','2026-03-02 10:44:39'),(73,'Operating System','Dead lock','2026-03-02 10:48:01'),(74,'Operating System','Dead lock','2026-03-02 10:49:36'),(75,'Operating System','Unit 1\r\nDead_lock','2026-03-02 10:52:25'),(76,'Operating System','UNIT 1:\r\nDead_lock','2026-03-02 10:54:25'),(77,'Operating System','UNIT 1 : Deadlock','2026-03-02 11:01:42'),(78,'loud Computing','UNIT I: Cloud Fundamentals\r\nCloud Concepts, Service Models (IaaS, PaaS, SaaS).\r\nDeployment Models: Public, Private, Hybrid Cloud.\r\n\r\nUNIT II: Virtualization\r\nHypervisors, Virtual Machines, Containers.\r\nDocker Basics, Containerization.\r\n\r\nUNIT III: Cloud Architecture\r\nCloud Storage, Cloud Networking.\r\nLoad Balancing, Auto Scaling.\r\n\r\nUNIT IV: Security in Cloud\r\nCloud Security Issues, IAM, Encryption.\r\nData Privacy, Compliance.\r\n\r\nUNIT V: Cloud Platforms\r\nAWS Overview, Azure Overview, Google Cloud Basics.\r\nServerless Computing, Cloud Monitoring.','2026-03-10 12:40:15');

